"""
Represents the 8x8 checkers board.
"""

class Board:
    def __init__(self):
        self._board = [[None] * 8 for _ in range(8)]
        self.initialize_board()

    def initialize_board(self):
        # Initialize the board with pieces
        for i in range(3):
            for j in range((i % 2), 8, 2):
                self._board[i][j] = Piece('black')
        for i in range(5, 8):
            for j in range((i % 2), 8, 2):
                self._board[i][j] = Piece('red')

    def get_piece(self, row, col):
        return self._board[row][col]

    def set_piece(self, row, col, piece):
        self._board[row][col] = piece

    def move_piece(self, start_row, start_col, end_row, end_col):
        piece = self.get_piece(start_row, start_col)
        if piece:
            self.set_piece(end_row, end_col, piece)
            self.set_piece(start_row, start_col, None)

    def __str__(self):
        return '\n'.join([' '.join([str(piece) if piece else '-' for piece in row]) for row in self._board])
```

