    def switch_turn(self):
        if self.current_player == 'red':
            self.current_player = 'black'
        else:
            self.current_player = 'red'

    def play_game(self):
        while True:
            print(self.board)
            click.echo(f"Player {self.current_player}'s turn. Enter move (e.g., a1-b2):")
            move_input = click.input().strip()
            if not move_input:
                break

            try:
                start_col, start_row, end_col, end_row = map(int, ''.join(filter(str.isdigit, move_input)))
                move = Move(start_row - 1, start_col - 1, end_row - 1, end_col - 1)
                self.board.move_piece(move.start[0], move.start[1], move.end[0], move.end[1])
                if move.is_capture():
                    # Handle capture logic
                    pass
            except (ValueError, IndexError):
                click.echo("Invalid move. Please try again.")

            self.switch_turn()

if __name__ == "__main__":
